parameters.jsCode:
const item = $input.first();
const J = item.json || {};
let raw = J.body ?? J.data ?? J.json ?? J;
if (typeof raw === 'string') {
  try { raw = JSON.parse(raw); } catch (e) { raw = {}; }
}
if (!raw || typeof raw !== 'object') raw = {};
if (!raw.task_id && J.task_id != null) raw = J;
const task_id = (raw.task_id ?? '').toString();
const title = (raw.title ?? 'Sem título').toString();
const description = (raw.description ?? '').toString();
return [{ json: { task_id, title, description } }];

